import scala.xml.{XML, Node}

import akka.http.scaladsl.server.HttpApp
import akka.http.scaladsl.server.Route
import akka.http.scaladsl.model.StatusCodes
import akka.http.scaladsl.server.Directives._

object XmlConfigService extends HttpApp {
  def parseXmlConfig(xmlString: String): Map[String, String] = {
    val xml = XML.loadString(xmlString)
    (xml \\ "setting").map { setting =>
      val key = (setting \ "@key").text
      val value = (setting \ "@value").text
      key -> value
    }.toMap
  }

  override def routes: Route =
    path("parseConfig") {
      post {
        entity(as[String]) { xmlString =>
          try {
            val configSettings = parseXmlConfig(xmlString)
            complete(StatusCodes.OK -> configSettings.toString)
          } catch {
            case e: Exception =>
              complete(StatusCodes.BadRequest -> s"Error parsing XML: ${e.getMessage}")
          }
        }
      }
    }
}

object Main extends App {
  XmlConfigService.startServer("localhost", 8080)
}